import React, { useMemo } from "react";
import "./nav.css";

let myRef = React.createRef();
function Nav() {
  const [isActive, setIsActive] = React.useState(false);
  useEffect(
    (handleClick = () => {
      console.log("click");
      setIsActive((current) => !current);
    })
  );

  const displayChange = () => {
    console.log("hovno");
    if (!isActive) {
      myRef.style.display = "block";
    } else {
      myRef.style.display = "none";
    }
  };
  return (
    <div>
      <div
        ref={myRef}
        value={isActive}
        className="pushMenu"
        onChange={(e) => displayChange(e.target.value)}
      ></div>
      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

export default Nav;

